local LxBaseHandler = require("LApp.handler.LxBaseHandler")
---@class LxRankHandler:LxBaseHandler
local LxRankHandler = classX("LxRankHandler", LxBaseHandler)

function LxRankHandler:Initialize()
    LxBaseHandler.Initialize(self)
end

function LxRankHandler:Dispose()
    LxBaseHandler.Dispose(self)
end

function LxRankHandler:ClearHandler()
    LxBaseHandler.ClearHandler(self)
end

function LxRankHandler:InitOk()
end

-- 完成登录后
function LxRankHandler:LoginOk()
    self:ReqNeedLikeRank()
end

function LxRankHandler:InitHandler()
    self:AddMsgHandler(LxProtoIds.RankResp, self.OnRankResp, self)
    self:AddMsgHandler(LxProtoIds.RankProfileResp, self.OnRankProfileResp, self)
    self:AddMsgHandler(LxProtoIds.RankMilestoneListResp, self.OnRankMilestoneListResp, self)
    self:AddMsgHandler(LxProtoIds.RankMilestoneUpdateResp, self.OnRankMilestoneUpdateResp, self)
    self:AddMsgHandler(LxProtoIds.RankMilestoneRewardResp, self.OnRankMilestoneRewardResp, self)
    self:AddMsgHandler(LxProtoIds.RankMilestoneDetailResp, self.OnRankMilestoneDetailResp, self)
end

---region s2c
function LxRankHandler:OnRankResp(pb)
    if pb.activityId == 0 then
        -- 非活动排行榜
        ModuleCenter.Rank:SetRankData(pb)
    end

    FireEvent(EventNames.RANK_LIST, pb)
end

function LxRankHandler:OnRankProfileResp(pb)

    ModuleCenter.Rank:SetRankProfile(pb)
    FireEvent(EventNames.RANK_LIST, pb)
    --local profileObjs = pb.profileObjs
end

---endregion s2c


---regin c2s
function LxRankHandler:RankReq(rankRefId, activityId, activityPageId, page, pageSize)
    local proto = LxProtoHelper.CreateProto(LxProtoIds.RankReq)
    proto.rankRefId = rankRefId
    if activityId then
        proto.activityId = activityId
    end
    if activityPageId then
        proto.activityPageId = activityPageId
    end
    if page then
        proto.page = page
    end
    if pageSize then
        proto.pageSize = pageSize
    end
    SendMessage(LxProtoIds.RankReq, proto)
end

---@param dataList V_pb_RankProfileObj[]
function LxRankHandler:RankProfileReq(dataList)
    local proto = LxProtoHelper.CreateProto(LxProtoIds.RankProfileReq)
    local profileObjs = proto.profileObjs
    for k, v in ipairs(dataList) do
        local profileObj = profileObjs:add()
        profileObj.rankRefId = v.rankRefId
        if v.activityId then
            profileObj.activityId = v.activityId
        end
        if v.activityPageId then
            profileObj.activityPageId = v.activityPageId
        end
    end
    SendMessage(LxProtoIds.RankProfileReq, proto)
end

---endregion c2s

-- 里程碑数据,登录下发
function LxRankHandler:OnRankMilestoneListResp(pb)
    self:DealWithComData(pb.milestones)
end

-- 里程碑进度变化推送
function LxRankHandler:OnRankMilestoneUpdateResp(pb)
    self:DealWithComData({ pb.milestone })
end

-- 领取里程碑奖励
function LxRankHandler:RankMilestoneRewardReq(rankRefId, refIds)
    local proto = LxProtoHelper.CreateProto(LxProtoIds.RankMilestoneRewardReq)
    proto.rankRefId = rankRefId
    for i,v in ipairs(refIds) do
        proto.refId:append(v)
    end
    SendMessage(LxProtoIds.RankMilestoneRewardReq, proto)
end

-- 领取里程碑奖励 返回
function LxRankHandler:OnRankMilestoneRewardResp(pb)
    self:DealWithComData({ pb.milestone })

    FireEvent(EventNames.REWARDS_RECEIVED, RewardRecvType.Rank, pb.rewardInfo)
end

-- 详细播报
function LxRankHandler:RankMilestoneDetailReq(rankRefId, refId)
    local proto = LxProtoHelper.CreateProto(LxProtoIds.RankMilestoneDetailReq)
    proto.rankRefId = rankRefId
    proto.refId = refId
    SendMessage(LxProtoIds.RankMilestoneDetailReq, proto)
end

-- 详细播报 返回
function LxRankHandler:OnRankMilestoneDetailResp(pb)
    FireEvent(EventNames.RANK_MILESTONE_DETAIL, {refId = pb.refId, dataList = pb.details})
end

-- 处理里程碑数据
function LxRankHandler:DealWithComData(milestones)
    local LxRankModule = ModuleCenter.Rank
    for _, v in ipairs(milestones) do
        for _, data in ipairs(v.entries) do
            LxRankModule:SetMilestorneData(data)
        end
    end
    FireEvent(EventNames.RANK_MILESTONE_CHANGE)
end

-- 请求所有，需要点赞的排行榜数据
function LxRankHandler:ReqNeedLikeRank()
    if not CtrlCenter.FuncOpen:IsFuncOpen(FuncOpnIdConst.Rank, FuncOpenTipsEnum.None) then
        return
    end
    local map = ModuleCenter.Rank:GetHadLikeRankIdMap()
    for rankRefId in pairs(map) do
        -- 只有前三才能点赞
        HandlerCenter.Rank:RankReq(rankRefId, 0, 0, 1, 3)
    end
end

return LxRankHandler
